411→func (h *Handler) handleSetup(resp Response, req Request) Response {
412→	if req.File == "" {
413→		resp.Status = "error"
414→		resp.Code = ErrInvalidRequest
415→		resp.Message = "setup command requires a file path"
416→		return resp
417→	}
418→	if req.Scope == "" {
419→		resp.Status = "error"
420→		resp.Code = ErrInvalidRequest
421→		resp.Message = "setup command requires a scope"
422→		return resp
423→	}
424→	if !req.Level.IsValid() {
425→		resp.Status = "error"
426→		resp.Code = ErrInvalidRequest
427→		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
428→		return resp
429→	}
430→
431→	if _, err := os.Stat(req.File); err != nil {
432→		resp.Status = "error"
433→		resp.Code = ErrFileNotFound
434→		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
435→		return resp
436→	}
437→
438→	var parentCtxJSON json.RawMessage
439→	if req.ParentContext != nil {
440→		data, err := json.Marshal(req.ParentContext)
441→		if err != nil {
442→			resp.Status = "error"
443→			resp.Code = ErrInternalError
444→			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
445→			return resp
446→		}
447→		parentCtxJSON = data
448→	}
449→
450→	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)
451→
452→	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
453→	if err != nil {
454→		resp.Status = "error"
455→		resp.Code = ErrInternalError
456→		resp.Message = fmt.Sprintf("setup failed: %v", err)
457→		return resp
458→	}
459→
460→	resp.Status = "setup"
461→	ctxCopy := json.RawMessage(ctx)
462→	resp.SetupContext = &ctxCopy
463→	return resp
464→}
