466→func (h *Handler) handleTeardown(resp Response, req Request) Response {
467→	if req.Scope == "" {
468→		resp.Status = "error"
469→		resp.Code = ErrInvalidRequest
470→		resp.Message = "teardown command requires a scope"
471→		return resp
472→	}
473→	if !req.Level.IsValid() {
474→		resp.Status = "error"
475→		resp.Code = ErrInvalidRequest
476→		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
477→		return resp
