 1→package generators
 2→
 3→import (
 4→	"context"
 5→	"encoding/json"
 6→	"fmt"
 7→	"sync"
 8→
 9→	extism "github.com/extism/go-sdk"
10→)
11→
12→// WasmCache loads and caches Extism plugins keyed by file path.
13→// Plugins are created on first use and reused for subsequent calls.
14→type WasmCache struct {
15→	mu      sync.Mutex
16→	plugins map[string]*extism.Plugin
17→}
18→
19→func NewWasmCache() *WasmCache {
20→	return &WasmCache{plugins: make(map[string]*extism.Plugin)}
21→}
22→
23→// Generate loads the WASM plugin at wasmPath (caching it), calls funcName
24→// with the JSON-encoded recipe as input, and parses the plugin output as
25→// a GeneratorResult. Returns (value, generator_id, recipe, error).
26→func (c *WasmCache) Generate(wasmPath, funcName string, recipe json.RawMessage) (json.RawMessage, string, json.RawMessage, error) {
27→	plugin, err := c.getOrLoad(wasmPath)
28→	if err != nil {
29→		return nil, "", nil, fmt.Errorf("loading WASM plugin %q: %w", wasmPath, err)
30→	}
31→
32→	// Use recipe as input; empty string if nil.
33→	var input []byte
34→	if recipe != nil {
35→		input = recipe
36→	}
37→
38→	_, output, err := plugin.Call(funcName, input)
39→	if err != nil {
40→		return nil, "", nil, fmt.Errorf("calling %q in %q: %w", funcName, wasmPath, err)
41→	}
42→
43→	var result GeneratorResult
44→	if err := json.Unmarshal(output, &result); err != nil {
45→		return nil, "", nil, fmt.Errorf("parsing generator output from %q: %w", wasmPath, err)
46→	}
47→
48→	return result.Value, result.ID, result.Recipe, nil
49→}
50→
51→func (c *WasmCache) getOrLoad(wasmPath string) (*extism.Plugin, error) {
52→	c.mu.Lock()
53→	defer c.mu.Unlock()
54→
55→	if p, ok := c.plugins[wasmPath]; ok {
56→		return p, nil
57→	}
58→
59→	manifest := extism.Manifest{
60→		Wasm: []extism.Wasm{
61→			extism.WasmFile{Path: wasmPath},
62→		},
63→	}
64→
65→	plugin, err := extism.NewPlugin(context.Background(), manifest, extism.PluginConfig{
66→		EnableWasi: true,
67→	}, nil)
68→	if err != nil {
69→		return nil, err
70→	}
71→
72→	c.plugins[wasmPath] = plugin
73→	return plugin, nil
74→}
75→
76→// Close frees all cached plugins.
77→func (c *WasmCache) Close() {
78→	c.mu.Lock()
79→	defer c.mu.Unlock()
80→
81→	for path, p := range c.plugins {
82→		p.Close(context.Background())
83→		delete(c.plugins, path)
84→	}
85→}
